from unittest import TestCase from applitools.selenium import Eyes from selenium import webdriver from AutomatedVisualTesting.base import APPLITOOLS_API_KEY import pytest import os
class BaseTest(TestCase): def setUp(self): self.driver = webdriver.Chrome() self.initialize_eyes() self.driver.get('https://applitools.com/helloworld') self.driver.maximize_window()
def tearDown(self): self.driver.quit()
def initialize_eyes(self): self.eyes = Eyes() self.eyes.api_key = APPLITOOLS_API_KEY return self.eyes
@pytest.mark.skipif(os.environ.get('RUN_SELENIUM') != '1', reason="Set RUN_SELENIUM=1 to run selenium-dependent tests locally") def test_applitools_smoke(): """Simple pytest-style smoke test to ensure pytest discovers tests.
This test is skipped by default because it requires a local Chrome webdriver and Applitools API key. It can be enabled locally. """ # Try to use webdriver-manager if available to avoid manual chromedriver installation. # Keep imports inside the test so module import doesn't fail in environments # that don't have webdriver-manager installed. options = None try: from selenium.webdriver.chrome.service import Service from selenium.webdriver.chrome.options import Options options = Options() # Use headless to allow running in CI/headless environments options.add_argument('--headless=new') options.add_argument('--no-sandbox') options.add_argument('--disable-dev-shm-usage') except Exception: # If options aren't available, proceed with defaults options = None
driver = None try: try: from webdriver_manager.chrome import ChromeDriverManager # Use webdriver-manager to provide a matching chromedriver driver = webdriver.Chrome(service=Service(ChromeDriverManager().install()), options=options) except Exception: # Fallback to default webdriver (requires chromedriver on PATH) driver = webdriver.Chrome(options=options) if options is not None else webdriver.Chrome()
driver.get('https://applitools.com/helloworld') # Wait for the page title to contain 'Applitools' (site may load dynamically) try: from selenium.webdriver.support.ui import WebDriverWait from selenium.webdriver.support import expected_conditions as EC WebDriverWait(driver, 15).until(EC.title_contains('Applitools')) except Exception: # If the title never appears, capture some debug info and raise a helpful error current_title = driver.title page_url = driver.current_url page_source_snippet = driver.page_source[:200] raise AssertionError(f"Expected 'Applitools' in page title but got '{current_title}'. URL={page_url} Source-start={page_source_snippet!r}") finally: if driver: driver.quit()

from unittest import TestCase from applitools.selenium import Eyes from selenium import webdriver from AutomatedVisualTesting.base import APPLITOOLS_API_KEY import pytest import os
class BaseTest(TestCase): def setUp(self): self.driver = webdriver.Chrome() self.initialize_eyes() self.driver.get('https://applitools.com/helloworld') self.driver.maximize_window()
def tearDown(self): self.driver.quit()
def initialize_eyes(self): self.eyes = Eyes() self.eyes.api_key = APPLITOOLS_API_KEY return self.eyes
@pytest.mark.skipif(os.environ.get('RUN_SELENIUM') != '1', reason="Set RUN_SELENIUM=1 to run selenium-dependent tests locally") def test_applitools_smoke(): """Simple pytest-style smoke test to ensure pytest discovers tests.
This test is skipped by default because it requires a local Chrome webdriver and Applitools API key. It can be enabled locally. """ # Try to use webdriver-manager if available to avoid manual chromedriver installation. # Keep imports inside the test so module import doesn't fail in environments # that don't have webdriver-manager installed. options = None try: from selenium.webdriver.chrome.service import Service from selenium.webdriver.chrome.options import Options options = Options() # Use headless to allow running in CI/headless environments options.add_argument('--headless=new') options.add_argument('--no-sandbox') options.add_argument('--disable-dev-shm-usage') except Exception: # If options aren't available, proceed with defaults options = None
driver = None try: try: from webdriver_manager.chrome import ChromeDriverManager # Use webdriver-manager to provide a matching chromedriver driver = webdriver.Chrome(service=Service(ChromeDriverManager().install()), options=options) except Exception: # Fallback to default webdriver (requires chromedriver on PATH) driver = webdriver.Chrome(options=options) if options is not None else webdriver.Chrome()
driver.get('https://applitools.com/helloworld') # Wait for the main page content to appear (the page builds itself dynamically) try: from selenium.webdriver.common.by import By from selenium.webdriver.support.ui import WebDriverWait from selenium.webdriver.support import expected_conditions as EC WebDriverWait(driver, 15).until(EC.presence_of_element_located((By.ID, 'main-content'))) except Exception: # If the main content never appears, capture debug info and raise a helpful error current_title = driver.title page_url = driver.current_url page_source_snippet = driver.page_source[:400] raise AssertionError( f"Expected main content to appear on Applitools helloworld page but it did not. " f"Title={current_title!r} URL={page_url} Source-start={page_source_snippet!r}")
# Ensure expected text is present somewhere in the rendered page if 'Applitools' not in driver.page_source: page_url = driver.current_url page_source_snippet = driver.page_source[:400] raise AssertionError(f"Expected 'Applitools' in page source but it was not found. URL={page_url} Source-start={page_source_snippet!r}") finally: if driver: driver.quit()
